/* ---------------------------------------------------------------------------
 * primitives.css — suite 13/P05
 * Shared styles for the five reusable primitives: Button, Link, Surface,
 * Card, Badge. Tokens-only — no project-specific copy or layout.
 * --------------------------------------------------------------------------- */

/* ---------- Button ---------- */
.p-btn {
  font-family: var(--t-mono);
  font-size: var(--t-base-size);
  line-height: var(--t-base-lh);
  letter-spacing: var(--t-normal);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--s-2);
  padding: var(--s-2) var(--s-4);
  border: 1px solid var(--line);
  background-color: transparent;
  color: var(--fg);
  cursor: pointer;
  transition: background-color var(--d-tap) var(--ease-out),
    border-color var(--d-fast) var(--ease-out),
    color var(--d-fast) var(--ease-out);
  border-radius: var(--r-1);
}

.p-btn:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.p-btn[disabled],
.p-btn[aria-disabled="true"] {
  cursor: not-allowed;
  opacity: 0.6;
}

/* size */
.p-btn--sm {
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  padding: var(--s-1) var(--s-3);
}
.p-btn--md {
  font-size: var(--t-base-size);
  line-height: var(--t-base-lh);
  padding: var(--s-2) var(--s-4);
}
.p-btn--lg {
  font-size: var(--t-md-size);
  line-height: var(--t-md-lh);
  padding: var(--s-3) var(--s-5);
}

/* variant */
.p-btn--solid {
  background-color: var(--fg);
  color: var(--fg-inverse);
  border-color: var(--fg);
}
.p-btn--solid:hover:not([disabled]) {
  background-color: var(--fg-mute);
  border-color: var(--fg-mute);
}
.p-btn--outline {
  background-color: transparent;
  border-color: var(--line-strong);
  color: var(--fg);
}
.p-btn--outline:hover:not([disabled]) {
  background-color: var(--bg-mute);
}
.p-btn--ghost {
  background-color: transparent;
  border-color: transparent;
  color: var(--fg);
}
.p-btn--ghost:hover:not([disabled]) {
  background-color: var(--bg-mute);
}

/* tone */
.p-btn--accent.p-btn--solid {
  background-color: var(--accent);
  border-color: var(--accent);
  color: var(--accent-fg);
}
.p-btn--accent.p-btn--solid:hover:not([disabled]) {
  background-color: var(--accent);
  filter: brightness(1.05);
}
.p-btn--accent.p-btn--outline {
  border-color: var(--accent);
  color: var(--accent);
}
.p-btn--accent.p-btn--outline:hover:not([disabled]) {
  background-color: var(--accent-mute);
}
.p-btn--accent.p-btn--ghost {
  color: var(--accent);
}
.p-btn--accent.p-btn--ghost:hover:not([disabled]) {
  background-color: var(--accent-mute);
}
.p-btn--danger.p-btn--solid {
  background-color: var(--error);
  border-color: var(--error);
  color: var(--fg-inverse);
}
.p-btn--danger.p-btn--outline {
  border-color: var(--error);
  color: var(--error);
}
.p-btn--danger.p-btn--ghost {
  color: var(--error);
}

.p-btn--loading {
  cursor: progress;
}

/* ---------- Link ---------- */
.p-link {
  color: var(--fg);
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
  transition: color var(--d-fast) var(--ease-out);
}
.p-link--underline {
  text-decoration: underline;
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
}
.p-link--subtle {
  text-decoration: none;
}
.p-link--subtle:hover {
  text-decoration: underline;
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
}
.p-link:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
.p-link__ext {
  margin-left: 0.15em;
}

/* ---------- Surface ---------- */
.p-surface {
  background-color: var(--bg);
}
.p-surface--base {
  background-color: var(--bg);
}
.p-surface--mute {
  background-color: var(--bg-mute);
}
.p-surface--raise {
  background-color: var(--bg-raise);
}
.p-surface--bordered {
  border: 1px solid var(--line);
}

/* ---------- Card ---------- */
.p-card {
  display: block;
  text-decoration: none;
  color: inherit;
  border: 1px solid var(--line);
  transition: border-color var(--d-fast) var(--ease-out),
    background-color var(--d-fast) var(--ease-out);
}
.p-card--link:hover,
.p-card--link:focus-visible {
  border-color: var(--line-strong);
}
.p-card--link:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}
.p-card__head {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: var(--s-3);
  margin-bottom: var(--s-3);
}
.p-card__title {
  font-family: var(--t-mono);
  font-size: var(--t-md-size);
  line-height: var(--t-md-lh);
  margin: 0;
}
.p-card__meta {
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  color: var(--fg-mute);
}
.p-card__body {
  font-family: var(--t-serif);
  font-size: var(--t-base-size);
  line-height: var(--t-base-lh);
}

/* ---------- Shell: SkipLink ---------- */
.shell-skiplink {
  position: fixed;
  top: var(--s-2);
  left: var(--s-2);
  z-index: var(--z-toast);
  padding: var(--s-2) var(--s-4);
  background-color: var(--bg-raise);
  color: var(--fg);
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  border: 1px solid var(--line-strong);
  border-radius: var(--r-1);
  text-decoration: none;
  transform: translateY(-200%);
  transition: transform var(--d-fast) var(--ease-out);
}

.shell-skiplink:focus,
.shell-skiplink:focus-visible {
  transform: translateY(0);
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

/* ---------- Shell: SiteHeader ---------- */
.shell-header {
  width: 100%;
  background-color: var(--bg);
  border-bottom: 1px solid var(--line);
}

.shell-header__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--s-4);
  height: 52px;
}

@media (min-width: 768px) {
  .shell-header__inner {
    height: 56px;
  }
}

.shell-header__identity {
  font-family: var(--t-mono);
  font-size: var(--t-md-size);
  line-height: var(--t-md-lh);
  font-weight: 600;
  color: var(--fg);
}

.shell-header__nav {
  display: none;
  align-items: center;
  gap: var(--s-5);
}

@media (min-width: 768px) {
  .shell-header__nav {
    display: flex;
  }
}

.shell-header__hamburger {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  padding: 0;
  background-color: transparent;
  border: 1px solid var(--line);
  border-radius: var(--r-1);
  color: var(--fg);
  font-family: var(--t-mono);
  font-size: var(--t-md-size);
  line-height: 1;
  cursor: pointer;
}

.shell-header__hamburger:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

@media (min-width: 768px) {
  .shell-header__hamburger {
    display: none;
  }
}

/* ---------- Shell: MobileDrawer ---------- */
.shell-drawer {
  position: fixed;
  inset: 0;
  z-index: var(--z-palette);
  pointer-events: none;
}

.shell-drawer[data-open="true"] {
  pointer-events: auto;
}

.shell-drawer__backdrop {
  position: fixed;
  inset: 0;
  background-color: var(--bg-overlay);
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--d-norm) var(--ease-out);
}

.shell-drawer__backdrop[data-open="true"] {
  opacity: 1;
  pointer-events: auto;
}

.shell-drawer__panel {
  position: fixed;
  top: 0;
  right: 0;
  width: min(320px, 80vw);
  height: 100dvh;
  background-color: var(--bg-mute);
  padding: var(--s-6);
  display: flex;
  flex-direction: column;
  gap: var(--s-5);
  transform: translateX(100%);
  transition: transform var(--d-norm) var(--ease-out);
  box-shadow: -1px 0 0 var(--line);
}

.shell-drawer__panel[data-open="true"] {
  transform: translateX(0);
}

.shell-drawer__close {
  align-self: flex-end;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  padding: 0;
  background-color: transparent;
  border: 1px solid var(--line);
  border-radius: var(--r-1);
  color: var(--fg);
  font-family: var(--t-mono);
  font-size: var(--t-md-size);
  line-height: 1;
  cursor: pointer;
}

.shell-drawer__close:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.shell-drawer__nav {
  display: flex;
  flex-direction: column;
  gap: var(--s-4);
}

/* ---------- Shell: ThemeToggle ---------- */
.shell-theme-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  padding: 0;
  background-color: transparent;
  border: 1px solid var(--line);
  border-radius: var(--r-1);
  color: var(--fg);
  font-family: var(--t-mono);
  font-size: var(--t-md-size);
  line-height: 1;
  cursor: pointer;
}

.shell-theme-toggle:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.shell-header__theme {
  margin-left: auto;
}

.shell-drawer__theme {
  display: flex;
  justify-content: flex-start;
}

.shell-drawer__nav .shell-navlink {
  font-size: var(--t-md-size);
}

@media (prefers-reduced-motion: reduce) {
  .shell-drawer__panel {
    transform: translateX(0);
    opacity: 0;
    transition: opacity var(--d-fast) var(--ease-out);
  }

  .shell-drawer__panel[data-open="true"] {
    opacity: 1;
  }

  .shell-drawer__backdrop {
    transition: opacity var(--d-fast) var(--ease-out);
  }
}

/* ---------- Shell: SiteFooter ---------- */
.shell-footer {
  width: 100%;
  background-color: var(--bg);
  border-top: 1px solid var(--line);
  margin-top: var(--s-7);
}

.shell-footer__inner {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: var(--s-3);
  padding-top: var(--s-5);
  padding-bottom: var(--s-5);
}

@media (min-width: 768px) {
  .shell-footer__inner {
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
    gap: var(--s-4);
  }
}

.shell-footer__copyright {
  margin: 0;
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  color: var(--fg-faint);
}

.shell-footer__links {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  color: var(--fg-faint);
}

.shell-footer__sep {
  color: var(--fg-faint);
  user-select: none;
}

/* ---------- Shell: NavLink ---------- */
.shell-navlink {
  font-family: var(--t-mono);
  font-size: var(--t-base-size);
  line-height: var(--t-base-lh);
  color: var(--fg-mute);
  text-decoration: none;
  text-decoration-color: transparent;
  text-decoration-thickness: 2px;
  text-underline-offset: 6px;
  transition: color var(--d-fast) var(--ease-out),
    text-decoration-color var(--d-fast) var(--ease-out);
}

.shell-navlink:hover {
  color: var(--fg);
  text-decoration: underline;
  text-decoration-color: var(--line-strong);
  text-decoration-thickness: 2px;
  text-underline-offset: 6px;
}

.shell-navlink:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.shell-navlink--active {
  color: var(--fg);
  text-decoration: underline;
  text-decoration-color: var(--accent);
  text-decoration-thickness: 2px;
  text-underline-offset: 6px;
  transition: none;
}

.shell-navlink--active:hover {
  text-decoration-color: var(--accent);
}

/* ---------- Badge ---------- */
.p-badge {
  display: inline-flex;
  align-items: center;
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: 1;
  padding: var(--s-1) var(--s-2);
  border: 1px solid var(--line);
  border-radius: 999px;
  background-color: transparent;
  color: var(--fg);
}
.p-badge--neutral {
  border-color: var(--line);
  color: var(--fg-mute);
}
.p-badge--accent {
  border-color: var(--accent);
  color: var(--accent);
}
.p-badge--warn {
  border-color: var(--warn);
  color: var(--warn);
}
.p-badge--ok {
  border-color: var(--ok);
  color: var(--ok);
}

